  }

  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const backupDir = path.resolve(path.join(process.cwd(), 'backups'));
  const expectedDir = path.resolve(process.cwd());

  // Prevent path traversal by verifying backupDir is within expectedDir
  if (!backupDir.startsWith(expectedDir)) {
